SELECT order_id, order_line_id, product_id, prod_item_id, modify_tag, start_date, end_date
FROM oc_order_product
WHERE order_id = #{orderId}
  AND order_line_id = #{orderLineId}
  AND modify_tag = #{modifyTag}

SELECT order_id, order_line_id, product_id, prod_item_id, element_id, element_item_id,
       element_type_code, is_main_element, modify_tag, start_date, end_date
FROM oc_order_product_element
WHERE order_id = #{orderId}
  AND order_line_id = #{orderLineId}
  AND product_id = #{productId}
  AND prod_item_id = #{prodItemId}
  AND element_type_code = #{elementTypeCode}
  AND modify_tag = #{modifyTag}
  AND is_main_element = #{isMainElement}
LIMIT 1

